import { TslDebug } from '@/components/TslDebug';
import TslDebugArea from '@/components/TslDebugArea';
import WebGpuCanvas from '@/components/WebGpuCanvas';
import { OrbitControls, PerspectiveCamera } from '@react-three/drei';
import { useThree } from '@react-three/fiber';
import * as React from 'react';
import { abs, Fn, If, positionLocal, rotateUV, time, vec2 } from 'three/tsl';
import * as THREE from 'three/webgpu';

declare namespace UpdateSize {
  export type Props = {
    width: number;
    height: number;
  };
}

function UpdateSize({ width, height }: UpdateSize.Props) {
  useThree((selector) => {
    const camera = selector.camera as THREE.PerspectiveCamera;
    camera.aspect = width / height;
    camera.updateProjectionMatrix();
  });
  return null;
}

export type Props = {};

function App01(props: Props) {
  const {} = props;

  const main = React.useMemo(
    () =>
      Fn(() => {
        const p = positionLocal.mul(2);

        p.assign(rotateUV(p.xy, time, vec2()));

        If(abs(p.x).greaterThan(0.95), () => {
          // @ts-ignore
          p.z = 1.0;
        });

        If(abs(p.y).greaterThan(0.95), () => {
          // @ts-ignore
          p.z = 1.0;
        });

        return p;
      }),
    []
  );

  return (
    <TslDebugArea>
      {(el) => (
        <WebGpuCanvas>
          <PerspectiveCamera
            makeDefault
            fov={53}
            aspect={el.clientWidth / el.clientHeight}
            near={0.1}
            far={10}
            position={[0, 0, 1]}
          />
          {/* <UpdateSize width={el.clientWidth} height={el.clientHeight} /> */}
          <mesh name="node-mesh">
            <planeGeometry args={[2, 1]} />
            <nodeMaterial fragmentNode={main()} />
            <TslDebug meshName={'node-mesh'} />
          </mesh>
          <axesHelper />
          <OrbitControls />
        </WebGpuCanvas>
      )}
    </TslDebugArea>
  );
}

export default React.memo(App01);
