import * as React from 'react';
import { TslDebugProvider, TslDebugViewer } from './TslDebug';
import Area, { Props as AreaProps } from './Area';

export type Props = Pick<AreaProps, 'children'> & {};

function TslDebugArea(props: Props) {
  const { children } = props;

  return (
    <TslDebugProvider>
      <Area>{children}</Area>
      <TslDebugViewer showVertexShader showFragmentShader />
    </TslDebugProvider>
  );
}

export default React.memo(TslDebugArea);
